        startDate: '2024-02-01T00:00:00Z',
        endDate: '2024-01-01T00:00:00Z',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as { error: string }).error).toMatch(/before/);
    });

    it('should return 400 for invalid granularity', () => {
      const response = handler.getDashboard({
        startDate: '2024-01-01T00:00:00Z',
        endDate: '2024-01-31T23:59:59Z',
        granularity: 'minute',
      });

      expect(response.status).toBe(400);
      expect((response.body as { error: string }).error).toMatch(/granularity/);
    });

    it('should return 400 for missing metric on getMetric', () => {
      const response = handler.getMetric({
        startDate: '2024-01-01T00:00:00Z',
        endDate: '2024-01-31T23:59:59Z',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
