      const totalOrders = body.summaries.find(s => s.metric === 'total-orders')!;
      expect(totalOrders.currentValue).toBe(100);

      const totalRevenue = body.summaries.find(s => s.metric === 'total-revenue')!;
      expect(totalRevenue.currentValue).toBe(1000);

      const activeUsers = body.summaries.find(s => s.metric === 'active-users')!;
      expect(activeUsers.currentValue).toBe(10);
    });

    it('should handle same startDate and endDate', () => {
      makeOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 50,
        createdAt: new Date('2024-01-15T12:00:00Z'),
